var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>왔군.</color>","JPN":"<color=#ff3636>来たか。</color>","ENG":"<color=#ff3636>So you've come.</color>","TWN":"<color=#ff3636>你來了。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"아포리아…….","JPN":"アポリア……","ENG":"Aporia...","TWN":"阿波利亞……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>또다시 이 몸의 앞을 가로막을 셈인가, 인간.</color>","JPN":"<color=#ff3636>また俺の邪魔をするつもりか、人間。</color>","ENG":"<color=#ff3636>Human, you wish to stop me again?</color>","TWN":"<color=#ff3636>你又打算阻擋我嗎，人類。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>재미있군.</color>","JPN":"<color=#ff3636>面白い。</color>","ENG":"<color=#ff3636>Interesting.</color>","TWN":"<color=#ff3636>真是有意思。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>그러고보니 기억이 나는 것 같기도 해.</color>","JPN":"<color=#ff3636>そういえば、微かに記憶がある。</color>","ENG":"<color=#ff3636>Come to think of it, I think I remember you.</color>","TWN":"<color=#ff3636>說起來，我好像想起來了。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>아무래도 너는 이 몸이 인간이었던 때, 이 몸과 아는 사이였던 모양이군.</color>","JPN":"<color=#ff3636>どうやらお前は、俺が人間だった頃に知り合いだったみたいだな。</color>","ENG":"<color=#ff3636>I'm guessing you and I were close when I was still a human.</color>","TWN":"<color=#ff3636>看來在這具軀殼還是人類的時候，我們互相認識。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>몇번이고, 몇번이고 이 몸의 업을 가로막는 이유는 틀림없이 그 사사로운 감정 때문이겠지.</color>","JPN":"<color=#ff3636>何度も何度も俺の仕事の邪魔をしてくるのは、きっとそれによる些細な感情のせいだろう。</color>","ENG":"<color=#ff3636>I'm sure your sentimental feelings are the reason you are trying to stop me time and time again.</color>","TWN":"<color=#ff3636>一次次，一次次妨礙我前進的原因，無疑是那些感情吧。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>그럼, 특별히 장단에 어울려 주도록 할까.</color>","JPN":"<color=#ff3636>では、特別にその茶番に付き合ってやるか。</color>","ENG":"<color=#ff3636>Then, perhaps I will play along this time.</color>","TWN":"<color=#ff3636>那麼，我要特別配合一下你嗎。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"무슨……?","JPN":"何を……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>스스로 이 쐐기를 몸에 찔러 넣어라.</color>","JPN":"<color=#ff3636>自分でこの楔を身体に突き刺せ。</color>","ENG":"<color=#ff3636>Stab this Wedge into your body.</color>","TWN":"<color=#ff3636>你自己把釘子插進身體裡吧。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>평범한 인간이라면, 정신이 붕괴하겠지만 너는 특별하다.</color>","JPN":"<color=#ff3636>普通の人間なら精神が崩壊するが、お前は特別だ。</color>","ENG":"<color=#ff3636>If you were an ordinary human, it would collapse your mind. But you are special.</color>","TWN":"<color=#ff3636>普通的人類會精神崩潰，但你是特別的。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>그대로 네가 가진 CRF를 모조리 소모시키면.</color>","JPN":"<color=#ff3636>そのままお前が持つCRFを消費し尽くせば、</color>","ENG":"<color=#ff3636>Let it consume every last drop of CRF you have.</color>","TWN":"<color=#ff3636>如果讓他消耗掉你所擁有的最後一點CRF，</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>너 역시 신인류가 되어, 이 몸과 업을 함께 할 수 있겠지.</color>","JPN":"<color=#ff3636>お前も新人類となり、俺と共にこの仕事を成していけるだろう。</color>","ENG":"<color=#ff3636>Then, you will become the new humankind, and together we will continue our duty.</color>","TWN":"<color=#ff3636>你也將成為新的人類，與我共創一番事業。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>선택은 너의 몫이다, 인간.</color>","JPN":"<color=#ff3636>お前が選べ、人間。</color>","ENG":"<color=#ff3636>The choice is yours, human.</color>","TWN":"<color=#ff3636>選擇權在你手裡，人類</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>또한 이것이 너에게 베풀 수 있는 마지막 자비다.</color>","JPN":"<color=#ff3636>そしてこれが、お前に施せる最後の慈悲である。</color>","ENG":"<color=#ff3636>Furthermore, this will be the last bit of mercy I will show.</color>","TWN":"<color=#ff3636>這也是我能給予你的最後一次憐憫。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"이런, 제기랄! 버텨! 버티라고!","JPN":"こんな、クソ！　耐えろ！　耐えろ！","ENG":"Goddammit! Hold! I said HOLD!","TWN":"該死！撐住！我說，撐住！！！"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"역장으로 침식체들을 막을게! 그동안 화력을 집중해!","JPN":"力場で侵食体をくい止めるわ！　そこに火力を集中させて！","ENG":"I'll stop the C.O.s with a stasis field! Focus fire while I do!","TWN":"我會用力場攔住侵蝕體！集中火力！"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"움직임이 멈췄어! 지금이야! 전 대원, 포격 준비!","JPN":"動きが止まった！　今だ！　全隊員、砲撃準備！","ENG":"They stopped! NOW! All units, ready your aim!","TWN":"他們停下了！就是現在！全體隊員，炮擊準備！"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"전 대원, 고지가 보인다!","JPN":"全隊員、終わりが見えたぞ！","ENG":"We're almost there!","TWN":"全體隊員，勝利就在眼前！"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"조금만 더 버티면, 조금만 더 버티면……!!","JPN":"あともう少しだ、あともう少し耐えれば……！！","ENG":"Hold on for a little longer... Just a little bit more...!!","TWN":"只要再多堅持一下，再多堅持一下……！！"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"나의 의지와 관계없이, 나와 연결된 아이기스를 통해 대원들의 목소리가 흘러들어온다.","JPN":"自分の意思とは無関係に、私と繋がっているアイギスを通じて隊員たちの声が流れてくる。","ENG":"Regardless of my will, I can hear the voices of my comrades through Aegis.","TWN":"不管願不願意，隊員們的聲音都會透過與我連接的埃癸斯流入我的耳中。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"여기서 아포리아를 쓰러트리지 않으면, 우리 세계에 미래는 없겠지.","JPN":"ここでアポリアを倒せなければ、私たちの世界に未来はないだろう。","ENG":"If I don't defeat Aporia here, there is no future for our world.","TWN":"如果不能在這裡打倒阿波利亞的話，我們的世界就沒有未來。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 그 무엇보다 중요한 건…….","JPN":"でも、何よりも大事なのは……","ENG":"But the most important thing is...","TWN":"但更重要的是……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그러니까…… 카린.","JPN":"だから……カリン。","ENG":"So... Karin.","TWN":"……卡琳。"},"stage":{"bg":"EXILER_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"다른 누구도 아닌, <color=#ffd34c>우리</color>의 손으로 대령님을 보내 드려야만 해.","JPN":"他の誰でもない、<color=#ffd34c>私たち</color>の手で、大佐を解放してさしあげなければならない。","ENG":"<color=#ffd34c>We</color> must be the ones who defeat Colonel.","TWN":"不是別人，<color=#ffd34c>我們</color>要親手送上校上路。"},"stage":{"bg":"EXILER_04","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"시끄러워, 침식체.","JPN":"うるさい、侵食体。","ENG":"Enough, C.O.","TWN":"你閉嘴，侵蝕體。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ENERGY_SMALL"},{"id":"L5_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그 이상, 더는 대령님의 죽음을 모욕하게 두지 않겠어.","JPN":"これ以上……大佐の死を侮辱することは許さない。","ENG":"I'm not going to let you desecrate Colonel's death any longer.","TWN":"我不會再讓你糟蹋上校的犧牲！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};